# Snapshot baseline tests - Generated by r-package-cleanup
# Purpose: Verify all exported functions exist and are callable
# Date: 2026-01-30

test_that("all exported functions exist and are functions", {
  exports <- getNamespaceExports("bertopic")
  
  for (fn_name in exports) {
    fn <- tryCatch(
      get(fn_name, envir = asNamespace("bertopic")),
      error = function(e) NULL
    )
    expect_true(!is.null(fn), 
      info = paste("Export", fn_name, "should exist"))
  }
})

test_that("core bertopic functions are exported", {
  core_fns <- c(
    "bert_topic", "bert_fit", "bert_fit_transform", "bert_transform",
    "bert_topic_info", "bert_topic_keywords", "bert_save", "bert_load",
    "import_bertopic", "sentence_transformer"
  )
  
  exports <- getNamespaceExports("bertopic")
  
  for (fn in core_fns) {
    expect_true(fn %in% exports, 
      info = paste(fn, "should be exported"))
  }
})

