# Additional structural tests

test_that("package imports reticulate correctly", {
  # Verify reticulate is a dependency via the loaded namespace
  imports <- getNamespaceImports("bertopic")
  expect_true("reticulate" %in% names(imports))
})

test_that("package info is correct", {
  pkg_info <- packageDescription("bertopic")
  expect_equal(pkg_info$Package, "bertopic")
  expect_true(!is.null(pkg_info$Version))
  expect_true(grepl("reticulate", pkg_info$Imports))
})

test_that("all bert_* functions have consistent prefix", {
  bert_fns <- grep("^bert_", getNamespaceExports("bertopic"), value = TRUE)
  expect_gt(length(bert_fns), 20)
  # All should be functions
  for (fn in bert_fns[1:5]) {  # Sample check
    expect_true(is.function(get(fn, envir = asNamespace("bertopic"))))
  }
})

test_that("all import_* functions have consistent prefix", {
  import_fns <- grep("^import_", getNamespaceExports("bertopic"), value = TRUE)
  expect_gt(length(import_fns), 5)
})

test_that("tbl_* functions are properly exported", {
  tbl_fns <- grep("^tbl_", getNamespaceExports("bertopic"), value = TRUE)
  expect_gt(length(tbl_fns), 5)
})

test_that("package has expected function categories", {
  exports <- getNamespaceExports("bertopic")
  
  # Check major categories exist
  bert_count <- sum(grepl("^bert_", exports))
  import_count <- sum(grepl("^import_", exports))
  tbl_count <- sum(grepl("^tbl_", exports))
  keybert_count <- sum(grepl("keybert", exports))
  polyfuzz_count <- sum(grepl("polyfuzz", exports))
  
  expect_gt(bert_count, 15)
  expect_gt(import_count, 5)
  expect_gt(tbl_count, 3)
  expect_gt(keybert_count, 3)
  expect_gt(polyfuzz_count, 3)
})
